import { useState } from 'react';

export interface AuthUser {
  id: string;
  email: string;
  full_name?: string;
}

const DEMO_USER: AuthUser = {
  id: 'demo-user-001',
  email: 'learner@genaimastery.com',
  full_name: 'GenAI Learner',
};

export const useAuth = () => {
  const [user, setUser] = useState<AuthUser | null>(DEMO_USER);
  const [loading] = useState(false);

  const signIn = async (_email: string, _password: string): Promise<{ error: { message: string } | null }> => {
    setUser(DEMO_USER);
    return { error: null };
  };

  const signUp = async (_email: string, _password: string, fullName: string): Promise<{ error: { message: string } | null }> => {
    setUser({ ...DEMO_USER, full_name: fullName });
    return { error: null };
  };

  const signOut = async () => {
    setUser(null);
  };

  return { user, loading, signIn, signUp, signOut };
};
