import React, { useState } from 'react';
import { useAuth } from '../hooks/useAuth';

const AuthPage: React.FC = () => {
  const { signIn, signUp } = useAuth();
  const [mode, setMode] = useState<'login' | 'signup'>('login');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [successMsg, setSuccessMsg] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(''); setSuccessMsg(''); setLoading(true);
    if (mode === 'login') {
      const { error } = await signIn(email, password);
      if (error) setError(error.message);
    } else {
      if (!fullName.trim()) { setError('Please enter your full name.'); setLoading(false); return; }
      const { error } = await signUp(email, password, fullName);
      if (error) setError(error.message);
      else setSuccessMsg('Account created! Check your email to confirm, then log in.');
    }
    setLoading(false);
  };

  return (
    <div style={{ minHeight: '100vh', background: 'var(--surface)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 24 }}>
      <div style={{ width: '100%', maxWidth: 460 }}>
        {/* Logo & Headline */}
        <div style={{ textAlign: 'center', marginBottom: 36 }}>
          <div style={{ fontSize: 48, marginBottom: 12 }}>🧠</div>
          <h1 className="display-title" style={{ fontSize: '2rem', color: 'var(--text-primary)', marginBottom: 8 }}>
            GenAI Mastery
          </h1>
          <p style={{ color: 'var(--text-secondary)', fontSize: '1rem' }}>
            Your complete Generative AI education — from zero to expert.
          </p>
        </div>

        {/* Card */}
        <div className="card" style={{ padding: 36 }}>
          {/* Tab switcher */}
          <div style={{ display: 'flex', background: 'var(--surface-2)', borderRadius: 'var(--radius)', padding: 4, marginBottom: 28 }}>
            {(['login', 'signup'] as const).map(m => (
              <button key={m} onClick={() => { setMode(m); setError(''); setSuccessMsg(''); }}
                style={{
                  flex: 1, padding: '8px 0', border: 'none', borderRadius: 'calc(var(--radius) - 2px)',
                  background: mode === m ? 'var(--white)' : 'transparent',
                  color: mode === m ? 'var(--text-primary)' : 'var(--text-muted)',
                  fontWeight: mode === m ? 700 : 500, fontSize: '0.9rem', cursor: 'pointer',
                  boxShadow: mode === m ? 'var(--shadow-sm)' : 'none',
                  transition: 'all 0.15s', fontFamily: 'var(--font-body)',
                }}>
                {m === 'login' ? 'Log In' : 'Create Account'}
              </button>
            ))}
          </div>

          {error && (
            <div style={{ background: 'var(--danger-light)', border: '1px solid #FECACA', borderRadius: 'var(--radius)', padding: '10px 14px', marginBottom: 20, fontSize: '0.875rem', color: 'var(--danger)' }}>
              ⚠️ {error}
            </div>
          )}
          {successMsg && (
            <div style={{ background: 'var(--success-light)', border: '1px solid #A7F3D0', borderRadius: 'var(--radius)', padding: '10px 14px', marginBottom: 20, fontSize: '0.875rem', color: 'var(--success)' }}>
              ✅ {successMsg}
            </div>
          )}

          <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: 18 }}>
            {mode === 'signup' && (
              <div>
                <label className="input-label">Full Name</label>
                <input className="input" type="text" placeholder="Ada Lovelace" value={fullName} onChange={e => setFullName(e.target.value)} required />
              </div>
            )}
            <div>
              <label className="input-label">Email Address</label>
              <input className="input" type="email" placeholder="you@example.com" value={email} onChange={e => setEmail(e.target.value)} required />
            </div>
            <div>
              <label className="input-label">Password</label>
              <input className="input" type="password" placeholder="••••••••" value={password} onChange={e => setPassword(e.target.value)} required minLength={6} />
            </div>
            <button type="submit" className="btn btn-primary btn-lg" disabled={loading} style={{ marginTop: 4, justifyContent: 'center' }}>
              {loading ? '⌛ Please wait...' : mode === 'login' ? '→ Log In' : '🚀 Start Learning'}
            </button>
          </form>

          {mode === 'login' && (
            <p style={{ textAlign: 'center', marginTop: 20, fontSize: '0.875rem', color: 'var(--text-muted)' }}>
              Don't have an account?{' '}
              <button onClick={() => setMode('signup')} style={{ background: 'none', border: 'none', color: 'var(--accent)', fontWeight: 600, cursor: 'pointer', fontSize: 'inherit' }}>
                Sign up free
              </button>
            </p>
          )}
        </div>

        {/* What you'll learn */}
        <div style={{ marginTop: 28, display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
          {['10 Complete Modules', '30+ Deep Topics', 'Hands-on Exercises', 'Quiz-Gated Progress'].map(f => (
            <div key={f} style={{ background: 'var(--white)', border: '1px solid var(--border)', borderRadius: 'var(--radius)', padding: '10px 14px', fontSize: '0.82rem', fontWeight: 600, color: 'var(--text-secondary)', display: 'flex', alignItems: 'center', gap: 6 }}>
              <span style={{ color: 'var(--success)' }}>✓</span> {f}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default AuthPage;
